import{_ as s,o as a,c as l,Q as e}from"./chunks/framework.3daba8ea.js";const E=JSON.parse('{"title":"kubectl create 与 kubectl apply 的区别","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Kubernetes/FAQ/apply和create区别.md","filePath":"packages/doc/src/DevOps/Kubernetes/FAQ/apply和create区别.md","lastUpdated":1702570157000}'),p={name:"doc/DevOps/Kubernetes/FAQ/apply和create区别.md"},n=e(`<h1 id="kubectl-create-与-kubectl-apply-的区别" tabindex="-1">kubectl create 与 kubectl apply 的区别 <a class="header-anchor" href="#kubectl-create-与-kubectl-apply-的区别" aria-label="Permalink to &quot;kubectl create 与 kubectl apply 的区别&quot;">​</a></h1><ul><li><a href="https://blog.csdn.net/yangchao1125/article/details/122486957" target="_blank" rel="noreferrer">参考</a></li></ul><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>在我们想要创建一个K8s资源的时候，既可以使用 create，又可以使用 apply，两者之间到底有什么不同呢？</p><h2 id="区别" tabindex="-1">区别 <a class="header-anchor" href="#区别" aria-label="Permalink to &quot;区别&quot;">​</a></h2><h3 id="kubectl-create" tabindex="-1">kubectl create <a class="header-anchor" href="#kubectl-create" aria-label="Permalink to &quot;kubectl create&quot;">​</a></h3><p>create 顾名思义就是创建新资源。这里我们需要注意的是，如果再次运行相同的命令，就会抛出错误，因为资源名称在名称空间中应该是唯一的。</p><p>第 1 次执行 kubectl create -f pod.xml 命令，正常结束，如下：</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">create</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">-f</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">pod.xml</span></span>
<span class="line"></span>
<span class="line"><span style="color:#B392F0;">pod/my-pod</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">created</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#6F42C1;">kubectl</span><span style="color:#24292E;"> </span><span style="color:#032F62;">create</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">-f</span><span style="color:#24292E;"> </span><span style="color:#032F62;">pod.xml</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6F42C1;">pod/my-pod</span><span style="color:#24292E;"> </span><span style="color:#032F62;">created</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>第 2 次执行 kubectl create -f pod.xml 命令，抛出错误，如下：</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">create</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">-f</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">pod.xml</span></span>
<span class="line"></span>
<span class="line"><span style="color:#B392F0;">Error</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">from</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">server</span><span style="color:#E1E4E8;"> (AlreadyExists): error when creating “pod.xml”: pods “my-pod” already exists</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#6F42C1;">kubectl</span><span style="color:#24292E;"> </span><span style="color:#032F62;">create</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">-f</span><span style="color:#24292E;"> </span><span style="color:#032F62;">pod.xml</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6F42C1;">Error</span><span style="color:#24292E;"> </span><span style="color:#032F62;">from</span><span style="color:#24292E;"> </span><span style="color:#032F62;">server</span><span style="color:#24292E;"> (AlreadyExists): error when creating “pod.xml”: pods “my-pod” already exists</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="kubectl-apply" tabindex="-1">kubectl apply <a class="header-anchor" href="#kubectl-apply" aria-label="Permalink to &quot;kubectl apply&quot;">​</a></h3><p>使配置在资源上生效。 这里分为两种情况，如下：</p><ol><li>资源本不存在：</li></ol><p>创建新资源。</p><ol><li>资源已存在：</li></ol><p>使配置在已存在的资源上生效（也就是更新资源的配置）。若配置没变化，则对应的资源也不会有什么改变。</p><p>第 1 次执行 kubectl apply -f pod.xml 命令，显示 created，如下：</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">apply</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">-f</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">pod.xml</span></span>
<span class="line"></span>
<span class="line"><span style="color:#B392F0;">pod/my-pod</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">created</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#6F42C1;">kubectl</span><span style="color:#24292E;"> </span><span style="color:#032F62;">apply</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">-f</span><span style="color:#24292E;"> </span><span style="color:#032F62;">pod.xml</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6F42C1;">pod/my-pod</span><span style="color:#24292E;"> </span><span style="color:#032F62;">created</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>第 2 次执行 kubectl apply -f pod.xml 命令，由于配置没改变，则显示 unchanged ，如下：</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">apply</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">-f</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">pod.xml</span></span>
<span class="line"><span style="color:#B392F0;">pod/my-pod</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">unchanged</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#6F42C1;">kubectl</span><span style="color:#24292E;"> </span><span style="color:#032F62;">apply</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">-f</span><span style="color:#24292E;"> </span><span style="color:#032F62;">pod.xml</span></span>
<span class="line"><span style="color:#6F42C1;">pod/my-pod</span><span style="color:#24292E;"> </span><span style="color:#032F62;">unchanged</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div>`,21),o=[n];function c(t,r,i,d,y,u){return a(),l("div",null,o)}const h=s(p,[["render",c]]);export{E as __pageData,h as default};
